@import './theme.css';
@import './utilities.css';

.react-aria-Calendar {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-2);
  overflow: auto;
  width: 100%;
  max-width: fit-content;
  color: var(--text-color);
  font: var(--font-size) system-ui;

  .months {
    display: flex;
    gap: var(--spacing-3);
  }

  .month {
    width: calc(var(--spacing-9) * 7);
    min-width: calc(var(--spacing-7) * 7);
    container-type: inline-size;
  }

  header {
    display: flex;
    align-items: center;
    margin: 0 var(--spacing-1) var(--spacing-4) var(--spacing-1);
    min-height: var(--spacing-8);

    .react-aria-CalendarHeading {
      flex: 1;
      margin: 0;
      text-align: center;
      font-size: var(--font-size-lg);
    }
  }

  .react-aria-CalendarGrid {
    border-spacing: 0;
  }

  [slot='errorMessage'] {
    font: var(--font-size-sm) system-ui;
    color: var(--invalid-color);
  }
}

.react-aria-CalendarHeaderCell {
  font-size: var(--font-size-sm);
}

.react-aria-CalendarCell {
  --gap: var(--spacing-1);
  width: calc((100cqw / 7) - var(--gap));
  aspect-ratio: 1;
  margin: calc(var(--gap) / 2);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: var(--font-size);
  text-align: center;
  border-radius: 9999px;
  cursor: default;
  forced-color-adjust: none;
  transition: scale 200ms;
  -webkit-tap-highlight-color: transparent;

  @media (min-resolution: 200dpi) {
    @container (width < 300px) {
      --gap: 0px;
    }
  }

  &[data-disabled] {
    opacity: 0.5;
  }

  &[data-pressed] {
    scale: 0.9;
  }

  &[data-unavailable] {
    text-decoration: line-through;
    color: var(--invalid-color);
  }

  &[data-invalid] {
    --button-color: var(--invalid-color);
  }
}

@import './theme.css';

.react-aria-Form {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-6);

  > .react-aria-Button {
    align-self: start;
  }
}

.react-aria-Form [role='alert'] {
  border: 2px solid var(--invalid-color);
  background: var(--overlay-background);
  border-radius: 6px;
  padding: 12px;
  max-width: 250px;
  outline: none;

  &:focus {
    outline: 2px solid var(--focus-ring-color);
    outline-offset: 2px;
  }

  h3 {
    margin-top: 0;
  }

  p {
    margin-bottom: 0;
  }
}

.react-aria-Label {
  display: block;
  font: var(--font-size) system-ui;
  color: var(--text-color);
  margin-bottom: var(--spacing-2);
  font-weight: 500;
}

.react-aria-FieldError {
  display: block;
  font: var(--font-size-sm) system-ui;
  color: var(--invalid-color);
  margin-top: var(--spacing-1);
  contain: inline-size;
}

.field-description {
  display: block;
  font: var(--font-size-sm) system-ui;
  margin-top: var(--spacing-1);
  contain: inline-size;

  [data-invalid] > & {
    display: none;
  }
}

.field-Button {
  background: var(--tint-200);
  color: var(--tint-1400);
  forced-color-adjust: none;
  border-radius: var(--radius-sm);
  border: none;
  margin-left: calc(-1 * var(--spacing-8) + 4px);
  height: calc(100% - 8px);
  aspect-ratio: 1/1;
  padding: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  transition-property: scale, background;
  transition-duration: 200ms;
  -webkit-tap-highlight-color: transparent;

  svg {
    width: var(--spacing-4);
    height: var(--spacing-4);
  }

  &:where([data-hovered], [data-pressed]) {
    background: var(--tint-300);
    color: var(--tint-1200);
  }

  @media (forced-colors: active) {
    background: Highlight;
    color: HighlightText;
  }

  &[data-pressed] {
    scale: 0.9;
  }

  &[data-focus-visible] {
    outline: 2px solid var(--focus-ring-color);
    outline-offset: 2px;
  }

  &[data-disabled] {
    background: none;
    color: var(--text-color-disabled);
  }
}

@import './theme.css';
@import './utilities.css';

.react-aria-TagGroup {
  display: flex;
  flex-direction: column;
  font: var(--font-size) system-ui;
  color: var(--text-color);

  [slot='errorMessage'] {
    margin-top: var(--spacing);
    font-size: var(--font-size-sm);
    color: var(--invalid-color);
  }
}

.react-aria-TagList {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-2);
}

.react-aria-Tag {
  --button-color: var(--gray);
  --button-gradient-size: 4px;
  text-shadow: none;
  forced-color-adjust: none;
  border-radius: 9999px;
  height: var(--spacing-5);
  padding: 0 var(--spacing-3);
  font: var(--font-size-sm) system-ui;
  cursor: default;
  display: flex;
  align-items: center;
  gap: var(--spacing-1);
  transition-property: scale, background, border-color, box-shadow, text-shadow;
  transition-duration: 200ms;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  -webkit-tap-highlight-color: transparent;

  &:has(.remove-button) {
    padding: 0 var(--spacing-1) 0 var(--spacing-2);
  }

  &[data-pressed] {
    scale: 0.96;
  }

  &[data-selected] {
    --button-color: var(--tint);
  }

  &[data-href] {
    text-decoration: none;
    cursor: pointer;
  }

  .remove-button {
    background: none;
    border: none;
    padding: 0;
    color: var(--gray-1000);
    transition: color 200ms;
    outline: none;
    border-radius: 100%;
    aspect-ratio: 1/1;
    height: calc(100% - 4px);
    display: flex;
    align-items: center;
    justify-content: center;
    transition-property: background, color, scale;
    transition-duration: 200ms;

    svg {
      width: calc(100% - 2px);
      height: calc(100% - 2px);
    }

    &:where([data-hovered], [data-pressed]) {
      background: var(--gray-300);
      color: var(--gray-1200);
    }

    @media (forced-colors: active) {
      background: ButtonFace;
      color: ButtonText;
    }

    &[data-pressed] {
      scale: 0.9;
    }

    &[data-focus-visible] {
      outline: 2px solid var(--focus-ring-color);
      outline-offset: -1px;
    }
  }

  &[data-selected] {
    .remove-button {
      color: inherit;
      &[data-hovered] {
        background: rgb(255 255 255 / 0.2);
      }
    }
  }
}

@import './theme.css';

.react-aria-ToastRegion {
  position: fixed;
  bottom: var(--spacing-4);
  right: var(--spacing-4);
  display: flex;
  flex-direction: column-reverse;
  gap: var(--spacing-2);
  border-radius: var(--radius-lg);
  outline: none;

  &[data-focus-visible] {
    outline: 2px solid var(--focus-ring-color);
    outline-offset: 2px;
  }
}

.react-aria-Toast {
  width: 230px;
  display: flex;
  align-items: center;
  gap: var(--spacing-4);
  background: var(--highlight-background);
  padding: var(--spacing-3) var(--spacing-4);
  border-radius: var(--radius-lg);
  outline: none;
  forced-color-adjust: none;
  view-transition-class: toast;

  &[data-focus-visible] {
    outline: 2px solid var(--focus-ring-color);
    outline-offset: 2px;
  }

  .react-aria-ToastContent {
    display: flex;
    flex-direction: column;
    flex: 1 1 auto;
    min-width: 0;
    font: var(--font-size) system-ui;

    [slot='title'] {
      font-weight: 600;
      color: var(--highlight-foreground);
    }

    [slot='description'] {
      font-size: var(--font-size-sm);
      color: var(--highlight-foreground);
    }
  }

  .react-aria-Button[slot='close'] {
    flex: 0 0 auto;
    background: none;
    border: none;
    appearance: none;
    border-radius: var(--radius-sm);
    height: var(--spacing-8);
    width: var(--spacing-8);
    color: var(--highlight-foreground);
    padding: 0;
    outline: none;
    -webkit-tap-highlight-color: transparent;

    &[data-hovered] {
      background: var(--tint-900);
      box-shadow: none;
    }

    &[data-focus-visible] {
      outline: 2px solid var(--highlight-foreground);
      outline-offset: 2px;
    }

    &[data-pressed] {
      background: var(--highlight-pressed);
      box-shadow: none;
    }
  }
}

::view-transition-new(.toast):only-child {
  animation: slide-in 400ms;
}

::view-transition-old(.toast):only-child {
  animation: slide-out 400ms;
  animation-fill-mode: forwards;
}

@keyframes slide-out {
  to {
    translate: 100% 0;
    opacity: 0;
    visibility: hidden;
  }
}

@keyframes slide-in {
  from {
    translate: 100% 0;
    opacity: 0;
  }
}

@import 'docs/src/css/custom-media.css';

@layer components {
  .DescriptionList {
    width: 100%;
    display: grid;
    grid-template-columns: auto 1fr;
    row-gap: var(--space-12);
  }

  .DescriptionListItem {
    position: relative;

    @media (--xs) {
      display: grid;
      grid-template-columns: subgrid;
      grid-column: span 3;
      align-items: start;
    }
  }

  .DescriptionTerm {
    font-size: var(--font-size-14);
    line-height: 1.25rem;
    font-weight: var(--font-weight-700);
    color: var(--color-foreground);
    white-space: nowrap;
    word-break: keep-all;
    position: relative;
    display: flex;
    align-items: center;
    margin-bottom: var(--space-4);

    @media (--xs) {
      font-weight: revert-layer;
      color: revert-layer;
      margin-bottom: 0;
    }

    &.separator {
      &::before {
        content: '';
        box-shadow: inset 0 1px 0 0 var(--gray-c2);
        position: absolute;
        top: 0;
        inset-inline: 0.75rem 1rem;
        height: 1px;
      }

      @media (--xs) {
        &::before {
          height: 0;
        }
      }
    }
  }

  .DescriptionListDetails {
    font-size: var(--font-size-14);
    line-height: 1.25rem;

    color: var(--color-foreground);
    grid-column: span 2;

    & p {
      margin: 0 !important;
    }
  }

  .DescriptionListInner {
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: start;
    padding-inline: 0.75rem;
    width: 100%;
    gap: var(--space-12);

    .CodeBlockRoot {
      margin: 0;
      max-width: 100%;
    }

    & > p:last-of-type {
      margin-bottom: 0;
    }

    .separator & {
      padding-top: var(--space-8);
    }

    @media (--xs) {
      min-height: 2.5rem;

      &,
      .separator & {
        padding: 0.625rem 0.75rem;
      }
    }
  }
}

h2,
h3 {
  margin-top: 12px;
  margin-bottom: 12px;
}

code {
  background-color: rgba(255, 229, 100, 0.2);
  padding: 0 3px;
  font-size: 0.94em;
  word-break: break-word;
}

sub {
  color: rgba(0, 0, 0, 0.47);
}

.header {
  padding: 8px 0;
  margin-bottom: 12px;
  max-width: 70%;
}

.subheader {
  font-size: 16px;
  margin-top: 12px;
  margin-bottom: 12px;
}

.layout {
  position: relative;
  max-width: 75%;
  margin: 36px auto 0;
}

.nav {
  margin: 12px auto 12px 16px;
  display: flex;
  align-items: center;
  gap: 4px;
  padding-top: 8px;
}

.nav .nav-link {
  text-decoration: none;
  cursor: pointer;
  padding: 12px;
  color: #000000;
  border: 2px solid #777777;
  border-bottom: none;
  border-top-left-radius: 4px;
  border-top-right-radius: 4px;
}

.nav .nav-link.active {
  text-decoration: none;
  cursor: pointer;
  padding: 12px;
  color: #fff;
  background-color: #777777;
  border: 2px solid #777777;
  border-bottom: none;
  border-top-left-radius: 4px;
  border-top-right-radius: 4px;
}

.toggler {
  margin-top: 16px;
  margin-bottom: 16px;
}

.cache-option-toggler {
  position: absolute;
  top: 24px;
  right: 0;
  background-color: #2d357a;
  color: #fff;
  border-radius: 4px;
  padding: 8px 16px 12px;
  border: 1px solid black;
}

.cache-option-toggler h4 {
  margin: 8px auto 16px;
  font-weight: 500;
}

.cache-option-toggler select {
  cursor: pointer;
  padding: 4px;
}

.body {
  min-height: 48vh;
  border: 2px solid #777777;
  padding: 12px 24px;
  border-radius: 4px;
}

.form {
  margin-top: 20px;
  max-width: 300px;
}

.form-control {
  display: flex;
  flex-direction: column;
  margin-bottom: 16px;
}

.form-control.checkbox {
  display: flex;
  flex-direction: column;
  margin-bottom: 12px;
}

.form-control label {
  font-weight: 500;
}

.form-control input {
  margin-top: 8px;
  font-size: 18px;
}

.form button[type="submit"] {
  padding: 8px 12px;
  font-size: 16px;
  cursor: pointer;
  background-color: #ff5d22;
  border-radius: 4px;
  border: none;
  color: #fff;
}

.toggle-button {
  padding: 8px 12px;
  font-size: 14px;
  font-weight: 500;
  cursor: pointer;
  background-color: #ff5d22;
  color: #fff;
  border-radius: 4px;
  border: none;
}

.visitor-data {
  margin-top: 16px;
  margin-bottom: 16px;
}

.visitor-data .details {
  max-height: 200px;
  overflow: scroll;
}

.clear-cache-button {
  cursor: pointer;
}

@mixin box-shadow($color, $fromLeft: true) {
  @if $fromLeft {
    // prettier-ignore
    box-shadow:
      -4px 0,
      4px 0,
      -4px 4px $color,
      0 4px,
      -8px 4px,
      -4px 8px,
      -8px 8px;
  } @else {
    // prettier-ignore
    box-shadow:
      -4px 0,
      4px 0,
      4px 4px $color,
      0 4px,
      8px 4px,
      4px 8px,
      8px 8px;
  }
}

.nes-balloon {
  @include rounded-corners();

  position: relative;
  display: inline-block;
  padding: 1rem 1.5rem;
  margin: 8px;
  margin-bottom: 30px;
  background-color: $background-color;

  > :last-child {
    margin-bottom: 0;
  }

  &::before,
  &::after {
    position: absolute;
    content: "";
  }

  &.is-dark {
    @include rounded-corners(true);

    color: $background-color;
    background: $base-color;
    border-image-outset: 2;
    box-shadow: 0 0 0 8px $base-color;

    &.from-left,
    &.from-right {
      &::before {
        background-color: $base-color;
        border-color: $background-color;
      }

      &::after {
        color: $background-color;
        background-color: $base-color;
      }
    }

    &.from-left {
      &::before {
        box-shadow: -5px 10px 0 6px $base-color;
      }
      &::after {
        @include box-shadow($base-color);
      }
    }

    &.from-right {
      &::before {
        box-shadow: 5px 10px 0 6px $base-color;
      }
      &::after {
        @include box-shadow($base-color, false);
      }
    }
  }

  &.from-left {
    &::before,
    &::after {
      left: 2rem;
    }

    &::before {
      bottom: -14px;
      width: 26px;
      height: 10px;
      background-color: $background-color;
      border-right: 4px solid $base-color;
      border-left: 4px solid $base-color;
    }

    &::after {
      bottom: -18px;
      width: 18px;
      height: 4px;
      margin-right: 8px;
      color: $base-color;
      background-color: $background-color;
      @include box-shadow($background-color);
    }
  }

  &.from-right {
    &::before,
    &::after {
      right: 2rem;
    }

    &::before {
      bottom: -14px;
      width: 26px;
      height: 10px;
      background-color: $background-color;
      border-right: 4px solid $base-color;
      border-left: 4px solid $base-color;
    }

    &::after {
      bottom: -18px;
      width: 18px;
      height: 4px;
      margin-left: 8px;
      background-color: $background-color;
      @include box-shadow($background-color, false);
    }
  }
}

$footer-breakpoint-tablet: 62.5em;
$footer-breakpoint-mobile: 40em;

.root {
  --docs-footer-height: 400px;

  @mixin smaller-than $footer-breakpoint-tablet {
    --docs-footer-height: 520px;
  }

  @mixin smaller-than $footer-breakpoint-mobile {
    --docs-footer-height: 380px;
  }
}

.spacer {
  height: var(--docs-footer-height);
}

.wrapper {
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  height: var(--docs-footer-height);
  background-color: var(--mantine-color-body);

  &[data-with-navbar] {
    padding-inline-start: calc(
      var(--docs-navbar-width) + var(--mantine-spacing-md) * 2 + var(--docs-inline-spacing)
    );
    padding-inline-end: calc(var(--mantine-spacing-md) * 2);

    @mixin smaller-than 1520px {
      padding-inline-start: calc(var(--docs-navbar-width) + var(--docs-inline-spacing));
    }

    @mixin smaller-than $docs-mdx-breakpoint {
      padding-inline-start: var(--docs-inline-spacing);
      padding-inline-end: var(--docs-inline-spacing);
    }
  }
}

.inner {
  padding-top: calc(var(--mantine-spacing-xl) * 2);
  padding-bottom: calc(var(--mantine-spacing-xl) * 2);
  display: flex;
  justify-content: space-between;

  @mixin smaller-than $footer-breakpoint-tablet {
    flex-direction: column;
  }

  @mixin smaller-than $footer-breakpoint-mobile {
    padding-bottom: var(--mantine-spacing-md);
  }
}

.logoSection {
  max-width: 300px;

  @mixin smaller-than $footer-breakpoint-tablet {
    margin-bottom: var(--mantine-spacing-xl);
  }

  @mixin smaller-than $footer-breakpoint-mobile {
    margin-bottom: 0;
  }
}

.description {
  margin-top: var(--mantine-spacing-xs);
  color: var(--mantine-color-dimmed);
}

.afterFooter {
  border-top: 1px solid light-dark(var(--mantine-color-gray-2), var(--mantine-color-dark-4));
  padding-top: var(--mantine-spacing-md);
}

.afterFooterNote {
  &,
  & a {
    color: var(--mantine-color-bright);
  }
}

.groups {
  display: flex;

  @mixin smaller-than $footer-breakpoint-mobile {
    display: none;
  }
}

.social {
  display: flex;

  @mixin smaller-than $footer-breakpoint-mobile {
    display: block;
  }
}

.socialButton {
  &:last-of-type {
    margin-inline-start: var(--mantine-spacing-md);
  }

  @mixin smaller-than $footer-breakpoint-mobile {
    width: 100%;
    margin-left: 0 !important;
    margin-right: 0 !important;
    margin-top: var(--mantine-spacing-sm);
  }
}

@keyframes slide {
  0% {
    transform: translate3d(0, 0, 0);
  }

  100% {
    transform: translate3d(0, -2076px, 0); /* The image width */
  }
}

.root {
  height: 692px;
  background-color: var(--mantine-color-body);
  position: relative;
  overflow: hidden;

  @mixin dark {
    background-color: var(--mantine-color-dark-7);
  }

  @mixin smaller-than $mantine-breakpoint-md {
    height: auto;
  }
}

.container {
  position: relative;
  padding-top: 200px;
  padding-bottom: var(--hp-block-spacing);

  @mixin smaller-than $mantine-breakpoint-md {
    padding-top: 80px;
  }
}

.image {
  height: calc(2052px * 3);
  position: absolute;
  width: 1000px;
  background-size: contain;
  z-index: 1;
  right: 0;
  top: 0;
  background-repeat: repeat-y;
  animation: slide 120s linear infinite;

  @mixin smaller-than $mantine-breakpoint-md {
    display: none;
  }
}

.main {
  position: relative;
  z-index: 3;
}

.overlay {
  position: absolute;
  inset: 0;
  z-index: 2;
  background: linear-gradient(-95deg, rgba(255, 255, 255, 0.5) 0%, rgba(255, 255, 255, 1) 60%);

  @mixin dark {
    background: linear-gradient(
      -95deg,
      alpha(var(--mantine-color-dark-7), 0.5) 0%,
      var(--mantine-color-dark-7) 60%
    );
  }
}

.action {
  height: 60px;
  width: 220px;
  border-radius: var(--mantine-radius-md);
  font-size: var(--mantine-font-size-lg);
  padding-inline: var(--mantine-spacing-lg);
  font-weight: 600;
  padding-top: 3px;
  border: 0;
  border-bottom: 3px solid transparent;

  transition:
    box-shadow 100ms ease,
    transform 100ms ease;

  @mixin hover {
    box-shadow: var(--mantine-shadow-md);
    transform: translateY(-1px) scale(1.01);
  }

  &[data-get-started] {
    background: var(--hp-primary-bg);
    box-shadow: var(--hp-primary-shadow);
    border-bottom: var(--hp-primary-border);
  }

  &[data-github] {
    background-color: var(--mantine-color-dark-7);
    color: var(--mantine-color-white);
    font-weight: 600;

    @mixin hover {
      background-color: var(--mantine-color-black);
    }

    @mixin dark {
      border-color: var(--mantine-color-dark-5);
      background-color: var(--mantine-color-gray-1);
      color: var(--mantine-color-black);
    }
  }

  @mixin smaller-than $mantine-breakpoint-xs {
    width: 100%;
  }
}

.actions {
  display: flex;
  gap: var(--mantine-spacing-lg);
